/**
 * Task report module.
 *
 * Formats a list of tasks into a plain-text report: a title header, one line
 * per task, an optional summary section, and a footer with totals. The public
 * surface is `formatReport` and the option/type exports; everything else is
 * internal machinery.
 */

export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  /** Only the "default" theme is registered. */
  theme?: string;
  /** Only "en" messages are provided. */
  locale?: string;
  /** Only plain text output is implemented; the enum anticipates markdown. */
  outputFormat?: "text";
}

// ---------------------------------------------------------------------------
// Theme and messages
// ---------------------------------------------------------------------------

const DEFAULT_THEME = {
  separator: "=",
  bullet: "-",
  doneMarker: "[x]",
  openMarker: "[ ]",
};

const MESSAGES: Record<string, Record<string, string>> = {
  en: {
    done: "done",
    total: "total",
    doneLabel: "Done",
    openLabel: "Open",
    hoursLabel: "Hours",
  },
};

function getMessage(locale: string, key: string): string {
  const table = MESSAGES[locale];
  if (!table) {
    throw new Error(`no messages for locale: ${locale}`);
  }
  const value = table[key];
  if (value === undefined) {
    throw new Error(`no message for key: ${key}`);
  }
  return value;
}

function formatHours(hours: number): string {
  return `${hours}h`;
}

// ---------------------------------------------------------------------------
// Rendering context
// ---------------------------------------------------------------------------

interface RenderContext {
  readonly input: ReportInput;
  readonly separator: string;
  readonly bullet: string;
  readonly locale: string;
}

interface SectionRenderer {
  readonly section: string;
  render(context: RenderContext): string[];
}

// ---------------------------------------------------------------------------
// Section renderers
// ---------------------------------------------------------------------------

class HeaderRenderer implements SectionRenderer {
  readonly section = "header";

  render(context: RenderContext): string[] {
    const title = context.input.title;
    const underline = context.separator.repeat(title.length);
    return [title, underline];
  }
}

class TaskListRenderer implements SectionRenderer {
  readonly section = "tasks";

  render(context: RenderContext): string[] {
    return context.input.tasks.map((task) => {
      const marker = task.done ? DEFAULT_THEME.doneMarker : DEFAULT_THEME.openMarker;
      const hours = formatHours(task.hours);
      return `${context.bullet} ${marker} ${task.title} (${hours})`;
    });
  }
}

class SummaryRenderer implements SectionRenderer {
  readonly section = "summary";

  render(context: RenderContext): string[] {
    let doneCount = 0;
    let openCount = 0;
    let totalHours = 0;
    for (const task of context.input.tasks) {
      if (task.done) {
        doneCount += 1;
      } else {
        openCount += 1;
      }
      totalHours += task.hours;
    }
    return [
      `${getMessage(context.locale, "doneLabel")}: ${doneCount}`,
      `${getMessage(context.locale, "openLabel")}: ${openCount}`,
      `${getMessage(context.locale, "hoursLabel")}: ${formatHours(totalHours)}`,
    ];
  }
}

class FooterRenderer implements SectionRenderer {
  readonly section = "footer";

  render(context: RenderContext): string[] {
    let doneCount = 0;
    let totalHours = 0;
    for (const task of context.input.tasks) {
      if (task.done) {
        doneCount += 1;
      }
      totalHours += task.hours;
    }
    const total = context.input.tasks.length;
    const doneWord = getMessage(context.locale, "done");
    const totalWord = getMessage(context.locale, "total");
    const hours = formatHours(totalHours);
    return [`${doneCount}/${total} ${doneWord}, ${hours} ${totalWord}`];
  }
}

// ---------------------------------------------------------------------------
// Renderer registry
// ---------------------------------------------------------------------------

const SECTION_RENDERERS: Record<string, SectionRenderer> = {
  header: new HeaderRenderer(),
  tasks: new TaskListRenderer(),
  summary: new SummaryRenderer(),
  footer: new FooterRenderer(),
};

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

const DEFAULT_REPORT_OPTIONS: Required<ReportOptions> = {
  separator: "=",
  bullet: "-",
  sections: ["header", "tasks", "footer"],
  theme: "default",
  locale: "en",
  outputFormat: "text",
};

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  const opts = { ...DEFAULT_REPORT_OPTIONS, ...(options ?? {}) };

  if (opts.theme !== "default") {
    throw new Error(`no theme registered under: ${opts.theme}`);
  }

  const context: RenderContext = {
    input,
    separator: opts.separator,
    bullet: opts.bullet,
    locale: opts.locale,
  };

  const lines: string[] = [];
  for (const section of opts.sections) {
    const renderer = SECTION_RENDERERS[section];
    if (!renderer) {
      throw new Error(`no renderer for section: ${section}`);
    }
    lines.push(...renderer.render(context));
  }

  return lines.join("\n");
}

